import React, { useState, useEffect } from 'react';
import { Search, Filter, ShoppingCart, Star, Clock, Plus, Minus } from 'lucide-react';
import styled from 'styled-components';
import { useCart } from '../context/CartContext';
import Button from '../components/UI/Button';
import Input from '../components/UI/Input';
import { Card, CardBody, CardTitle } from '../components/UI/Card';
import theme from '../styles/theme';

const MenuContainer = styled.div`
  min-height: calc(100vh - 140px);
  padding: ${theme.spacing.lg};
`;

const MenuHeader = styled.div`
  margin-bottom: ${theme.spacing.xl};
`;

const MenuTitle = styled.h1`
  font-size: ${theme.typography.fontSize['3xl']};
  font-weight: ${theme.typography.fontWeight.bold};
  color: ${theme.colors.primary};
  margin-bottom: ${theme.spacing.md};
`;

const SearchFilterSection = styled.div`
  display: flex;
  gap: ${theme.spacing.lg};
  margin-bottom: ${theme.spacing.xl};
  flex-wrap: wrap;

  @media (max-width: ${theme.breakpoints.tablet}) {
    flex-direction: column;
  }
`;

const SearchContainer = styled.div`
  flex: 1;
  min-width: 250px;
  position: relative;
`;

const SearchIcon = styled.div`
  position: absolute;
  left: ${theme.spacing.md};
  top: 50%;
  transform: translateY(-50%);
  color: ${theme.colors.gray[400]};
  pointer-events: none;
`;

const SearchInput = styled(Input)`
  padding-left: ${theme.spacing.xl};
`;

const FilterContainer = styled.div`
  display: flex;
  gap: ${theme.spacing.md};
  align-items: center;
`;

const CategoryFilter = styled.select`
  padding: ${theme.spacing.md};
  border: 1px solid ${theme.colors.gray[300]};
  border-radius: ${theme.borderRadius.md};
  background-color: ${theme.colors.white};
  font-size: ${theme.typography.fontSize.md};
  min-width: 150px;

  &:focus {
    outline: none;
    border-color: ${theme.colors.primary};
    box-shadow: 0 0 0 3px rgba(26, 54, 93, 0.1);
  }
`;

const MenuGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: ${theme.spacing.xl};
  margin-bottom: ${theme.spacing.xl};
`;

const FoodCard = styled(Card)`
  overflow: hidden;
  transition: transform ${theme.transitions.normal};

  &:hover {
    transform: translateY(-5px);
  }
`;

const FoodImage = styled.div`
  height: 200px;
  background: linear-gradient(135deg, ${theme.colors.gray[200]} 0%, ${theme.colors.gray[300]} 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  color: ${theme.colors.gray[500]};
  position: relative;
`;

const FoodBadge = styled.div`
  position: absolute;
  top: ${theme.spacing.md};
  right: ${theme.spacing.md};
  background-color: ${theme.colors.primary};
  color: ${theme.colors.white};
  padding: ${theme.spacing.xs} ${theme.spacing.sm};
  border-radius: ${theme.borderRadius.md};
  font-size: ${theme.typography.fontSize.sm};
  font-weight: ${theme.typography.fontWeight.medium};
`;

const FoodContent = styled(CardBody)`
  padding: ${theme.spacing.lg};
`;

const FoodHeader = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: start;
  margin-bottom: ${theme.spacing.md};
`;

const FoodTitle = styled.h3`
  font-size: ${theme.typography.fontSize.lg};
  font-weight: ${theme.typography.fontWeight.semibold};
  color: ${theme.colors.secondary};
  margin: 0;
`;

const FoodPrice = styled.div`
  font-size: ${theme.typography.fontSize.xl};
  font-weight: ${theme.typography.fontWeight.bold};
  color: ${theme.colors.primary};
`;

const FoodDescription = styled.p`
  color: ${theme.colors.gray[600]};
  margin-bottom: ${theme.spacing.md};
  line-height: 1.5;
  font-size: ${theme.typography.fontSize.sm};
`;

const FoodMeta = styled.div`
  display: flex;
  align-items: center;
  gap: ${theme.spacing.md};
  margin-bottom: ${theme.spacing.md};
  font-size: ${theme.typography.fontSize.sm};
  color: ${theme.colors.gray[500]};
`;

const Rating = styled.div`
  display: flex;
  align-items: center;
  gap: ${theme.spacing.xs};
  color: ${theme.colors.warning};
`;

const AddToCartSection = styled.div`
  display: flex;
  align-items: center;
  gap: ${theme.spacing.md};
`;

const QuantityControl = styled.div`
  display: flex;
  align-items: center;
  gap: ${theme.spacing.sm};
  border: 1px solid ${theme.colors.gray[300]};
  border-radius: ${theme.borderRadius.md};
  overflow: hidden;
`;

const QuantityButton = styled.button`
  background: ${theme.colors.gray[100]};
  border: none;
  padding: ${theme.spacing.sm};
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background-color ${theme.transitions.fast};

  &:hover {
    background: ${theme.colors.gray[200]};
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
`;

const QuantityDisplay = styled.div`
  padding: ${theme.spacing.sm} ${theme.spacing.md};
  font-weight: ${theme.typography.fontWeight.medium};
  min-width: 40px;
  text-align: center;
`;

const LoadingMessage = styled.div`
  text-align: center;
  padding: ${theme.spacing.xl};
  color: ${theme.colors.gray[600]};
  font-size: ${theme.typography.fontSize.lg};
`;

const EmptyMessage = styled.div`
  text-align: center;
  padding: ${theme.spacing.xl};
  color: ${theme.colors.gray[600]};
  font-size: ${theme.typography.fontSize.lg};
`;

const MenuPage = () => {
  const [foods, setFoods] = useState([]);
  const [filteredFoods, setFilteredFoods] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('all');
  const [loading, setLoading] = useState(true);
  const { addItem, updateItemQuantity, getItemQuantity } = useCart();

  const categories = [
    { value: 'all', label: 'All Categories' },
    { value: 'appetizers', label: 'Appetizers' },
    { value: 'main-course', label: 'Main Course' },
    { value: 'desserts', label: 'Desserts' },
    { value: 'beverages', label: 'Beverages' },
    { value: 'salads', label: 'Salads' }
  ];

  useEffect(() => {
    // Mock data - in real app, this would come from API
    const mockFoods = [
      {
        id: 1,
        name: 'Classic Burger',
        description: 'Juicy beef patty with fresh vegetables and special sauce',
        price: 12.99,
        category: 'main-course',
        rating: 4.5,
        prepTime: '15-20 min',
        popular: true,
        image: '/images/foods/burger.jpg'
      },
      {
        id: 2,
        name: 'Cheese Burger',
        description: 'Double cheese with juicy beef patty and fresh vegetables',
        price: 14.99,
        category: 'main-course',
        rating: 4.7,
        prepTime: '15-20 min',
        popular: true,
        image: '/images/foods/cheese-burger.jpg'
      },
      {
        id: 3,
        name: 'Margherita Pizza',
        description: 'Fresh mozzarella, tomatoes, and basil on crispy dough',
        price: 14.99,
        category: 'main-course',
        rating: 4.8,
        prepTime: '20-25 min',
        popular: true,
        image: '/images/foods/pizza.jpg'
      },
      {
        id: 4,
        name: 'Pizza Margherita',
        description: 'Classic Italian pizza with fresh basil and mozzarella',
        price: 16.99,
        category: 'main-course',
        rating: 4.9,
        prepTime: '20-25 min',
        image: '/images/foods/pizza-margherita.jpg'
      },
      {
        id: 5,
        name: 'Caesar Salad',
        description: 'Crisp romaine lettuce with parmesan and caesar dressing',
        price: 8.99,
        category: 'salads',
        rating: 4.3,
        prepTime: '10-15 min',
        image: '/images/foods/salad.jpg'
      },
      {
        id: 6,
        name: 'Chicken Wings',
        description: 'Crispy chicken wings with your choice of sauce',
        price: 10.99,
        category: 'appetizers',
        rating: 4.6,
        prepTime: '15-20 min',
        image: '/images/foods/chicken.jpg'
      },
      {
        id: 7,
        name: 'French Fries',
        description: 'Golden crispy french fries with sea salt',
        price: 4.99,
        category: 'appetizers',
        rating: 4.4,
        prepTime: '10-15 min',
        image: '/images/foods/french-fries.jpg'
      },
      {
        id: 8,
        name: 'Onion Rings',
        description: 'Crispy battered onion rings with dipping sauce',
        price: 5.99,
        category: 'appetizers',
        rating: 4.5,
        prepTime: '12-18 min',
        image: '/images/foods/onion-rings.jpg'
      },
      {
        id: 9,
        name: 'Mozzarella Sticks',
        description: 'Golden fried mozzarella sticks with marinara sauce',
        price: 7.99,
        category: 'appetizers',
        rating: 4.6,
        prepTime: '10-15 min',
        image: '/images/foods/mozzarella-stick.jpg'
      },
      {
        id: 10,
        name: 'Lasagna',
        description: 'Classic Italian lasagna with layers of pasta and cheese',
        price: 15.99,
        category: 'main-course',
        rating: 4.8,
        prepTime: '25-30 min',
        image: '/images/foods/lasagna.jpg'
      },
      {
        id: 11,
        name: 'Pasta',
        description: 'Creamy pasta with fresh herbs and parmesan',
        price: 13.99,
        category: 'main-course',
        rating: 4.5,
        prepTime: '20-25 min',
        image: '/images/foods/pasta.jpg'
      },
      {
        id: 12,
        name: 'Sushi',
        description: 'Fresh sushi rolls with wasabi and ginger',
        price: 18.99,
        category: 'main-course',
        rating: 4.9,
        prepTime: '15-20 min',
        popular: true,
        image: '/images/foods/sushi.jpg'
      },
      {
        id: 13,
        name: 'Japanese Cake Roll',
        description: 'Delicious Japanese cake roll with cream filling',
        price: 8.99,
        category: 'desserts',
        rating: 4.7,
        prepTime: '5-10 min',
        image: '/images/foods/dessert.jpg'
      },
      {
        id: 14,
        name: 'Brownies',
        description: 'Rich chocolate brownies with walnuts',
        price: 6.99,
        category: 'desserts',
        rating: 4.8,
        prepTime: '5 min',
        image: '/images/foods/brownies.jpg'
      },
      {
        id: 15,
        name: 'Brownie Milkshake',
        description: 'Thick brownie milkshake with whipped cream',
        price: 5.99,
        category: 'beverages',
        rating: 4.6,
        prepTime: '5 min',
        image: '/images/foods/drinks.jpg'
      },
      {
        id: 16,
        name: 'Coca Cola',
        description: 'Refreshing Coca Cola soft drink',
        price: 2.99,
        category: 'beverages',
        rating: 4.2,
        prepTime: '2 min',
        image: '/images/foods/coca-cola.jpg'
      }
    ];

    setTimeout(() => {
      setFoods(mockFoods);
      setFilteredFoods(mockFoods);
      setLoading(false);
    }, 1000);
  }, []);

  useEffect(() => {
    let filtered = foods;

    if (searchTerm) {
      filtered = filtered.filter(food =>
        food.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        food.description.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (selectedCategory !== 'all') {
      filtered = filtered.filter(food => food.category === selectedCategory);
    }

    setFilteredFoods(filtered);
  }, [searchTerm, selectedCategory, foods]);

  const handleAddToCart = (food) => {
    addItem(food.id);
  };

  const handleUpdateQuantity = (foodId, change) => {
    const currentQuantity = getItemQuantity(foodId);
    const newQuantity = Math.max(0, currentQuantity + change);
    if (newQuantity === 0) {
      // Item will be removed from cart when quantity is 0
      return;
    }
    updateItemQuantity(foodId, newQuantity);
  };

  return (
    <MenuContainer>
      <MenuHeader>
        <MenuTitle>Our Menu</MenuTitle>
        <p style={{ color: theme.colors.gray[600] }}>
          Choose from our wide selection of delicious dishes
        </p>
      </MenuHeader>

      <SearchFilterSection>
        <SearchContainer>
          <SearchIcon>
            <Search size={20} />
          </SearchIcon>
          <SearchInput
            type="text"
            placeholder="Search for food..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </SearchContainer>

        <FilterContainer>
          <Filter size={20} style={{ color: theme.colors.gray[500] }} />
          <CategoryFilter
            value={selectedCategory}
            onChange={(e) => setSelectedCategory(e.target.value)}
          >
            {categories.map(category => (
              <option key={category.value} value={category.value}>
                {category.label}
              </option>
            ))}
          </CategoryFilter>
        </FilterContainer>
      </SearchFilterSection>

      {filteredFoods.length === 0 ? (
        <EmptyMessage>
          No items found matching your criteria.
        </EmptyMessage>
      ) : (
        <MenuGrid>
          {filteredFoods.map(food => {
            const quantity = getItemQuantity(food.id);
            return (
              <FoodCard key={food.id}>
                <FoodImage>
                  <img 
                    src={food.image} 
                    alt={food.name}
                    style={{ 
                      width: '100%', 
                      height: '100%', 
                      objectFit: 'cover',
                      borderRadius: '8px 8px 0 0'
                    }} 
                  />
                  {food.popular && <FoodBadge>Popular</FoodBadge>}
                </FoodImage>

                <FoodContent>
                  <FoodHeader>
                    <FoodTitle>{food.name}</FoodTitle>
                    <FoodPrice>${food.price.toFixed(2)}</FoodPrice>
                  </FoodHeader>

                  <FoodDescription>{food.description}</FoodDescription>

                  <FoodMeta>
                    <Rating>
                      <Star size={16} fill="currentColor" />
                      <span>{food.rating}</span>
                    </Rating>
                    <div style={{ display: 'flex', alignItems: 'center', gap: theme.spacing.xs }}>
                      <Clock size={16} />
                      <span>{food.prepTime}</span>
                    </div>
                  </FoodMeta>

                  <AddToCartSection>
                    {quantity > 0 ? (
                      <>
                        <QuantityControl>
                          <QuantityButton
                            onClick={() => handleUpdateQuantity(food.id, -1)}
                            disabled={quantity === 0}
                          >
                            <Minus size={16} />
                          </QuantityButton>
                          <QuantityDisplay>{quantity}</QuantityDisplay>
                          <QuantityButton
                            onClick={() => handleUpdateQuantity(food.id, 1)}
                          >
                            <Plus size={16} />
                          </QuantityButton>
                        </QuantityControl>
                        <Button
                          onClick={() => handleAddToCart(food)}
                          style={{ flex: 1 }}
                        >
                          <ShoppingCart size={16} style={{ marginRight: theme.spacing.xs }} />
                          Add More
                        </Button>
                      </>
                    ) : (
                      <Button
                        onClick={() => handleAddToCart(food)}
                        fullWidth
                      >
                        <ShoppingCart size={16} style={{ marginRight: theme.spacing.xs }} />
                        Add to Cart
                      </Button>
                    )}
                  </AddToCartSection>
                </FoodContent>
              </FoodCard>
            );
          })}
        </MenuGrid>
      )}
    </MenuContainer>
  );
};

export default MenuPage;
